def mnu_file_save_clicked():
    import sys
    filename = getattr(sys, '_shared_filename', 'untitled.py')
    try:
        with open(filename, 'w') as f:
            f.write(txt_editor.caption)
        msgbox(f'Saved successfully to {filename}')
    except Exception as e:
        msgbox(f'Save Error: {e}')

def mnu_selection_comment_clicked():
    if getattr(txt_editor, 'sel_start', None) is None or getattr(txt_editor, 'sel_end', None) is None:
        msgbox('No selection found.')
        return
    s_row = txt_editor.sel_start[0]
    e_row = txt_editor.sel_end[0]
    if s_row > e_row:
        s_row, e_row = e_row, s_row
    lines = txt_editor.caption.splitlines(keepends=True)
    new_lines = []
    for i, line in enumerate(lines):
        if s_row <= i <= e_row:
            if line.strip() and not line.lstrip().startswith('#'):
                indent = line[:len(line) - len(line.lstrip())]
                new_lines.append(indent + '#' + line.lstrip())
            else:
                new_lines.append(line)
        else:
            new_lines.append(line)
    txt_editor.caption = ''.join(new_lines)

def mnu_selection_uncomment_clicked():
    if getattr(txt_editor, 'sel_start', None) is None or getattr(txt_editor, 'sel_end', None) is None:
        msgbox('No selection found.')
        return
    s_row = txt_editor.sel_start[0]
    e_row = txt_editor.sel_end[0]
    if s_row > e_row:
        s_row, e_row = e_row, s_row
    lines = txt_editor.caption.splitlines(keepends=True)
    new_lines = []
    for i, line in enumerate(lines):
        if s_row <= i <= e_row:
            stripped = line.lstrip()
            if stripped.startswith('#'):
                indent = line[:len(line) - len(stripped)]
                content = stripped[1:]
                if content.startswith(' '):
                    content = content[1:]
                new_lines.append(indent + content)
            else:
                new_lines.append(line)
        else:
            new_lines.append(line)
    txt_editor.caption = ''.join(new_lines)

